      setInputChatMessages(prev => [...prev, {
        role: 'assistant',
        content: aiResponse
      }]);

      setIsProcessing(false);
    }, 800);
  };

  const addNewSection = () => {
    if (activeSections.length >= 6) return;

    // Find sections from MOCK_SECTIONS that aren't currently active
    const currentIds = activeSections.map(s => s.id);
    const availableSections = MOCK_SECTIONS.filter(s => !currentIds.includes(s.id));

    let newSection;
    if (availableSections.length > 0) {
      // Add first available standard section
      newSection = availableSections[0];
    } else {
      // All standard sections present, create custom one
      newSection = {
        id: `section-${Date.now()}`,
        name: 'Custom Section',
        content: 'Enter content for this section.',
        subsections: []
      };
    }

    const updatedSections = [...activeSections, newSection];
    setActiveSections(updatedSections);
    setGeneratedPrompt(updatedSections.map(s => s.content).join('\n\n'));
  };

  const deleteSection = (sectionId) => {
    const updatedSections = activeSections.filter(s => s.id !== sectionId);
    setActiveSections(updatedSections);
    setGeneratedPrompt(updatedSections.map(s => s.content).join('\n\n'));
  };

  const renderContent = () => {
    if (currentState === STATES.INPUT) {
      return (
        <div className="h-full flex flex-col">
          <div className="text-gray-400 text-sm mb-6 flex-shrink-0">
            What do you want to build?
          </div>

          {!inputChatMode ? (
            <textarea
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              className="flex-1 bg-transparent text-white placeholder-gray-600 text-base leading-relaxed resize-none border-none focus:outline-none"
              placeholder="Example: I need to analyze customer feedback and identify common themes..."
              autoFocus
            />
          ) : (
            <div className="flex-1 overflow-y-auto space-y-3 pr-2">
              {inputChatMessages.map((msg, idx) => (
                <div 
                  key={idx}
                  className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
                >
                  <div className={`
                    max-w-[80%] rounded-2xl px-4 py-3 text-sm
                    ${msg.role === 'user'
                      ? 'bg-cyan-500 text-white'
                      : msg.role === 'system'
                        ? 'bg-gray-800/60 text-gray-400 border border-gray-700'
                        : 'bg-gray-800 text-gray-200'
                    }
                  `}>
                    {msg.content}
                  </div>
                </div>
              ))}
              {isProcessing && (
                <div className="flex justify-start">
                  <div className="bg-gray-800 rounded-2xl px-4 py-3">
                    <div className="flex gap-1">
                      <div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce" style={{animationDelay: '0ms'}} />
                      <div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce" style={{animationDelay: '150ms'}} />
                      <div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce" style={{animationDelay: '300ms'}} />
                    </div>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      );
    }

    if (currentState === STATES.GENERATING) {
      return (
        <div className="h-full flex flex-col items-center justify-center">
          <div className="w-12 h-12 border-2 border-cyan-500 border-t-transparent rounded-full animate-spin mb-4" />
          <div className="text-gray-400 text-sm">Structuring your prompt...</div>
        </div>
      );
    }

    if (currentState === STATES.REVIEW || currentState === STATES.ANALYSIS_OVERVIEW) {
      return (
        <div className="h-full overflow-y-auto">
          <div className="relative">
            {/* Main prompt box */}
            <div className={`
              bg-gray-800/40 rounded-xl p-5 border transition-all
              ${editMode ? 'border-cyan-500' : 'border-gray-700'}
            `}>
              {currentState === STATES.ANALYSIS_OVERVIEW ? (
                // Analysis mode - sections are clickable with separators
                <div className="space-y-4">
                  {activeSections.map((section, idx) => (
                    <div key={section.id}>
                      {idx > 0 && <div className="border-t border-gray-700/50 my-4" />}
                      <div
                        onClick={() => handleSectionClick(section.id)}
                        className={`
                          relative cursor-pointer transition-all rounded-lg p-3 -mx-3
                          ${selectedSectionId === section.id
                            ? 'bg-cyan-500/10 border border-cyan-500/30'
                            : 'hover:bg-gray-800/40'
                          }
                        `}
                      >
                        <div className="text-xs text-cyan-400 mb-2 font-medium">{section.name}</div>
                        <div className="text-white text-sm leading-relaxed">{section.content}</div>

                        {/* Delete button - appears when section is highlighted */}
                        {selectedSectionId === section.id && (
                          <button
                            onClick={(e) => {
                              e.stopPropagation();
                              deleteSection(section.id);
                              setSelectedSectionId(null);
                              setClickedOnce(null);
                            }}
                            className="absolute top-3 right-3 p-1.5 bg-gray-900/80 hover:bg-red-600 rounded-lg transition-colors"
                            title="Delete section"
                          >
                            <Trash2 className="w-3.5 h-3.5 text-gray-400 hover:text-white" />
                          </button>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                // Review mode - editable or plain text
                editMode ? (
                  <textarea
                    value={editContent}
                    onChange={(e) => setEditContent(e.target.value)}
                    className="w-full bg-transparent text-white text-sm leading-relaxed resize-none border-none focus:outline-none min-h-[300px]"
                    autoFocus
                  />
                ) : (
                  <div className="text-white text-sm leading-relaxed whitespace-pre-wrap">
                    {generatedPrompt}
                  </div>
                )
              )}

              {/* Copy + Edit buttons - bottom center */}
              <div className="flex justify-center gap-2 mt-6 pt-4 border-t border-gray-700/30">
                {editMode ? (
                  <>
                    <button
                      onClick={() => setEditMode(false)}
                      className="px-4 py-2 text-sm text-gray-400 hover:text-white transition-colors"
                    >
                      Cancel
                    </button>
                    <button
                      onClick={saveManualEdit}
                      className="px-4 py-2 text-sm bg-cyan-500 hover:bg-cyan-600 text-white rounded-lg transition-colors flex items-center gap-1.5"
                    >
                      <Check className="w-4 h-4" />
                      Save
                    </button>
                  </>
                ) : (
                  <>
                    <button
                      onClick={copyPrompt}
                      className="flex items-center gap-1.5 px-3 py-1.5 text-xs text-gray-400 hover:text-cyan-400 bg-gray-800/60 hover:bg-gray-800 rounded-lg transition-colors"
                    >
                      <Copy className="w-3.5 h-3.5" />
                      <span>{copiedMessage ? 'Copied!' : 'Copy'}</span>
                    </button>
                    {/* Edit button only in REVIEW mode, not in ANALYSIS_OVERVIEW */}
                    {currentState === STATES.REVIEW && (
                      <button
                        onClick={toggleEditMode}
                        className="flex items-center gap-1.5 px-3 py-1.5 text-xs text-gray-400 hover:text-cyan-400 bg-gray-800/60 hover:bg-gray-800 rounded-lg transition-colors"
                      >
                        <Edit3 className="w-3.5 h-3.5" />
                        <span>Edit</span>
                      </button>
                    )}
                  </>
                )}
              </div>
            </div>

            {/* Section management - only in analysis mode */}
            {currentState === STATES.ANALYSIS_OVERVIEW && !editMode && (
              <div className="mt-6 flex items-center justify-center gap-3">
                <div className="text-xs text-gray-500">
                  {activeSections.length} of 6 sections
                </div>

                <button
                  onClick={addNewSection}
                  disabled={activeSections.length >= 6}
                  className={`
                    px-4 py-2 border border-dashed rounded-lg text-xs transition-all flex items-center gap-1.5
                    ${activeSections.length >= 6
                      ? 'border-gray-800 text-gray-600 cursor-not-allowed'
                      : 'border-gray-700 hover:border-cyan-500/50 text-gray-500 hover:text-cyan-400'
                    }
                  `}
                >
                  <Plus className="w-4 h-4" />
                  {activeSections.length >= 6 ? 'Max reached' : 'Add Section'}
                </button>
              </div>
            )}
          </div>
        </div>
      );
    }

    if (currentState === STATES.ANALYSIS_SECTION) {
      // Section detail view (existing functionality)
      const section = activeSections.find(s => s.id === focusedSection);
      if (!section) return null;

      return (
        <div className="h-full overflow-y-auto space-y-4 pr-2">
          {/* Quick actions */}
          <div className="grid grid-cols-2 gap-2">
            <button 
              onClick={() => handleQuickAction('expand')}
              disabled={isRegenerating || (!highlightedSection && !highlightedSubsection)}
              className="py-3 bg-gray-800/40 hover:bg-gray-800/60 border border-gray-700 rounded-lg text-sm text-gray-300 hover:text-cyan-400 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Expand
            </button>
            <button 
              onClick={() => handleQuickAction('condense')}
              disabled={isRegenerating || (!highlightedSection && !highlightedSubsection)}
              className="py-3 bg-gray-800/40 hover:bg-gray-800/60 border border-gray-700 rounded-lg text-sm text-gray-300 hover:text-cyan-400 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Condense
            </button>
          </div>

          {/* Main section content */}
          <div 
            onClick={() => setHighlightedSection(!highlightedSection)}
            className={`
              relative bg-gray-800/60 rounded-xl p-5 border transition-all cursor-pointer
              ${highlightedSection
                ? 'border-cyan-500 bg-cyan-500/10'
                : 'border-gray-700 hover:border-gray-600'
              }
            `}
          >
            <div className="text-white text-base leading-relaxed">
              {section.content}
            </div>
          </div>

          {/* Subsections */}
          {section.subsections && section.subsections.length > 0 ? (
            <div className="space-y-2">
              <div className="text-xs text-gray-500 uppercase tracking-wider">Components</div>
              {section.subsections.map((subsection) => (
                <button
                  key={subsection.id}
                  onClick={() => {
                    setHighlightedSubsection(subsection.id === highlightedSubsection ? null : subsection.id);
                    setHighlightedSection(false);
                  }}
                  className={`
                    w-full text-left rounded-lg p-3 transition-all
                    ${highlightedSubsection === subsection.id
                      ? 'bg-cyan-500/20 border-2 border-cyan-500'
                      : 'bg-gray-800/40 hover:bg-gray-800/60 border border-gray-700'
                    }
                  `}
                >
                  <div className="text-gray-300 text-sm mb-1">{subsection.name}</div>
                  <div className="text-gray-500 text-xs">{subsection.content}</div>
                </button>
              ))}
            </div>
          ) : (
            <div className="text-center py-4 text-xs text-gray-600">
              No sub-components for this section
            </div>
          )}

          {/* Chat */}
          {chatMode && (
            <div className="space-y-3 max-h-[40vh] overflow-y-auto">
              <div className="text-xs text-gray-500 uppercase tracking-wider">Chat with Claude</div>

              {chatMessages.map((msg, idx) => (
                <div 
                  key={idx}
                  className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
                >
                  <div className={`
                    max-w-[80%] rounded-2xl px-4 py-3 text-sm
                    ${msg.role === 'user'
                      ? 'bg-cyan-500 text-white'
                      : msg.role === 'system'
                        ? 'bg-gray-800/60 text-gray-400 border border-gray-700'
                        : 'bg-gray-800 text-gray-200'
                    }
                  `}>
                    {msg.content}
                  </div>
                </div>
              ))}

              {isProcessing && (
                <div className="flex justify-start">
                  <div className="bg-gray-800 rounded-2xl px-4 py-3">
                    <div className="flex gap-1">
                      <div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce" style={{animationDelay: '0ms'}} />
                      <div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce" style={{animationDelay: '150ms'}} />
                      <div className="w-2 h-2 bg-cyan-400 rounded-full animate-bounce" style={{animationDelay: '300ms'}} />
                    </div>
                  </div>
                </div>
              )}
              <div ref={chatEndRef} />
            </div>
          )}
        </div>
      );
    }

    return null;
  };

  const getButtonConfig = () => {
    if (currentState === STATES.INPUT) {
      const hasContent = inputText.trim() || (inputChatMode && inputChatMessages.some(m => m.role === 'user'));

      return {
        left: { 
          icon: inputChatMode ? X : Sparkles,
          action: toggleInputChatMode,
          active: inputChatMode
        },
        center: { 
          icon: ArrowUp, 
          action: handleGenerate,
          disabled: !hasContent
        },
        right: { icon: Camera, action: () => setShowUploadMenu(true) }
      };
    }

    if (currentState === STATES.REVIEW) {
      return {
        left: { icon: Sparkles, action: enterAnalysis },
        center: { icon: Plus, disabled: true },
        right: { icon: Camera, action: () => setShowUploadMenu(true) }
      };
    }

    if (currentState === STATES.ANALYSIS_OVERVIEW) {
      return {
        left: { icon: ChevronLeft, action: exitAnalysis },
        center: { icon: Plus, disabled: true },
        right: { icon: Camera, action: () => setShowUploadMenu(true) }
      };
    }

    if (currentState === STATES.ANALYSIS_SECTION) {
      return {
        left: { icon: ChevronLeft, action: backToOverview },
        center: { 
          icon: chatMode ? X : Sparkles,
          action: toggleChatMode,
          active: chatMode
        },
        right: { icon: Camera, action: () => setShowUploadMenu(true) }
      };
    }

    return {
      left: { icon: Plus, disabled: true },
      center: { icon: ArrowUp, disabled: true },
      right: { icon: X, disabled: true }
    };
  };

  const buttons = getButtonConfig();

  return (
    <div className="h-screen flex flex-col bg-gradient-to-b from-gray-900 via-black to-gray-900">
      {/* Header */}
      <div className="flex justify-between items-center p-4 border-b border-gray-800/50">
        <div className="flex items-center gap-3">
          <div className="text-white font-medium tracking-tight">PromptEngine</div>
          {(currentState === STATES.ANALYSIS_OVERVIEW || currentState === STATES.ANALYSIS_SECTION) && (
            <button
              onClick={revertChanges}
              className="flex items-center gap-1.5 px-2.5 py-1 text-xs text-gray-400 hover:text-cyan-400 bg-gray-800/60 hover:bg-gray-800 rounded-lg transition-colors"
              title="Revert all changes"
            >
              <RotateCcw className="w-3.5 h-3.5" />
              <span>Revert</span>
            </button>
          )}
        </div>
        <div className="flex items-center gap-3">
          <div className="text-xs px-2 py-1 rounded-full text-gray-500">
            {currentState === STATES.ANALYSIS_OVERVIEW && 'analysis'}
            {currentState === STATES.ANALYSIS_SECTION && 'section'}
            {currentState === STATES.REVIEW && 'review'}
            {currentState === STATES.INPUT && 'input'}
          </div>

          {/* Three-dot menu */}
          <div className="relative">
            <button
              onClick={() => setShowMenu(!showMenu)}
              className="p-1.5 text-gray-400 hover:text-cyan-400 hover:bg-gray-800/60 rounded-lg transition-colors"
              title="Menu"
            >
              <MoreVertical className="w-4 h-4" />
            </button>

            {showMenu && (
              <>
                {/* Backdrop */}
                <div 
                  className="fixed inset-0 z-10"
                  onClick={() => setShowMenu(false)}
                />

                {/* Dropdown */}
                <div className="absolute right-0 mt-2 w-48 bg-gray-800 border border-gray-700 rounded-lg shadow-xl z-20 overflow-hidden">
                  <button
                    onClick={() => handleMenuAction('save')}
                    className="w-full flex items-center gap-3 px-4 py-3 text-sm text-gray-300 hover:bg-gray-700/50 transition-colors text-left"
                  >
                    <Save className="w-4 h-4" />
                    <span>Save Prompt</span>
                  </button>
                  <button
                    onClick={() => handleMenuAction('templates')}
                    className="w-full flex items-center gap-3 px-4 py-3 text-sm text-gray-300 hover:bg-gray-700/50 transition-colors text-left border-t border-gray-700/50"
                  >
                    <FileText className="w-4 h-4" />
                    <span>View Templates</span>
                  </button>
                  <button
                    onClick={() => handleMenuAction('delete')}
                    className="w-full flex items-center gap-3 px-4 py-3 text-sm text-red-400 hover:bg-red-500/10 transition-colors text-left border-t border-gray-700/50"
                  >
                    <Trash2 className="w-4 h-4" />
                    <span>Delete & Restart</span>
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      </div>

      {/* Main content */}
      <div className="flex-1 px-6 py-6 overflow-hidden flex flex-col">
        {renderContent()}
      </div>

      {/* Chat input */}
      {currentState === STATES.INPUT && inputChatMode && (
        <div className="px-6 pb-4">
          <input
            ref={chatInputRef}
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleInputChatMessage()}
            placeholder="Type your message..."
            className="w-full bg-gray-800 text-white placeholder-gray-500 rounded-xl px-4 py-3 text-sm border border-gray-700 focus:border-cyan-500 focus:outline-none"
          />
        </div>
      )}

      {currentState === STATES.ANALYSIS_SECTION && chatMode && (
        <div className="px-6 pb-4">
          <input
            ref={chatInputRef}
            type="text"
            value={chatInput}
            onChange={(e) => setChatInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
            placeholder="Type your request..."
            className="w-full bg-gray-800 text-white placeholder-gray-500 rounded-xl px-4 py-3 text-sm border border-gray-700 focus:border-cyan-500 focus:outline-none"
          />
        </div>
      )}

      {/* Bottom prompt text */}
      <div className="px-6 pb-8 pt-4">
        <div className="text-center text-gray-500 text-sm mb-6">
          {currentState === STATES.INPUT && !inputChatMode && 'Describe what you need, or tap sparkle to chat'}
          {currentState === STATES.INPUT && inputChatMode && 'Chatting about your prompt'}
          {currentState === STATES.REVIEW && 'Tap sparkle to analyze'}
          {currentState === STATES.ANALYSIS_OVERVIEW && 'Click section once to highlight, twice to edit'}
          {currentState === STATES.ANALYSIS_SECTION && !chatMode && 'Tap sparkle to chat'}
          {currentState === STATES.ANALYSIS_SECTION && chatMode && 'Chatting with Claude'}
        </div>

        {/* Three-button nav */}
        <div className="flex justify-center items-center gap-8">
          <button
            onClick={buttons.left.action}
            disabled={buttons.left.disabled}
            className={`
              w-14 h-14 rounded-full flex items-center justify-center transition-all active:scale-95
              ${buttons.left.disabled 
                ? 'opacity-30 cursor-not-allowed bg-gray-800/80 border border-gray-700/50'
                : 'bg-gray-800/80 hover:bg-gray-800 border border-gray-700/50'
              }
            `}
          >
            {buttons.left.icon && <buttons.left.icon className="w-5 h-5 text-gray-400" />}
          </button>

          <button
            onClick={buttons.center.action}
            disabled={buttons.center.disabled}
            className={`
              w-16 h-16 rounded-full flex items-center justify-center shadow-lg transition-all active:scale-95
              ${buttons.center.disabled
                ? 'opacity-30 cursor-not-allowed bg-gray-800/80'
                : buttons.center.active 
                  ? 'bg-cyan-500 hover:bg-cyan-600' 
                  : 'bg-white hover:bg-gray-100'
              }
            `}
          >
            {buttons.center.icon && (
              <buttons.center.icon className={`w-6 h-6 ${buttons.center.active ? 'text-white' : 'text-black'}`} />
            )}
          </button>

          <button
            onClick={buttons.right.action}
            disabled={buttons.right.disabled}
            className="w-14 h-14 rounded-full bg-gray-800/80 hover:bg-gray-800 border border-gray-700/50 flex items-center justify-center transition-all active:scale-95"
          >
            {buttons.right.icon && <buttons.right.icon className="w-5 h-5 text-gray-400" />}
          </button>
        </div>
      </div>

      {/* Upload menu */}
      {showUploadMenu && (
        <div 
          className="absolute inset-0 bg-black/60 backdrop-blur-sm flex items-end"
          onClick={() => setShowUploadMenu(false)}
        >
          <div 
            className="w-full bg-gray-900 rounded-t-3xl p-6 space-y-3 animate-slide-up"
            onClick={(e) => e.stopPropagation()}
          >
            <button
              onClick={() => {
                fileInputRef.current?.click();
                setShowUploadMenu(false);
              }}
              className="w-full flex items-center gap-4 p-4 bg-gray-800 hover:bg-gray-700 rounded-xl transition-colors"
            >
              <div className="w-10 h-10 rounded-full bg-cyan-500/20 flex items-center justify-center">
                <Upload className="w-5 h-5 text-cyan-400" />
              </div>
              <div className="text-left">
                <div className="text-white text-sm font-medium">Upload File</div>
                <div className="text-xs text-gray-400">Add document or image</div>
              </div>
            </button>

            <button
              onClick={handleTakePhoto}
              className="w-full flex items-center gap-4 p-4 bg-gray-800 hover:bg-gray-700 rounded-xl transition-colors"
            >
              <div className="w-10 h-10 rounded-full bg-cyan-500/20 flex items-center justify-center">
                <Camera className="w-5 h-5 text-cyan-400" />
              </div>
              <div className="text-left">
                <div className="text-white text-sm font-medium">Take Photo</div>
                <div className="text-xs text-gray-400">Capture with camera</div>
              </div>
            </button>

            <button
              onClick={() => setShowUploadMenu(false)}
              className="w-full py-3 text-gray-400 text-sm"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      <input
        ref={fileInputRef}
        type="file"
        onChange={handleFileUpload}
        accept="image/*,.pdf,.doc,.docx,.txt"
        className="hidden"
      />

      <style jsx>{`
        @keyframes slide-up {
          from { transform: translateY(100%); }
          to { transform: translateY(0); }
        }
        .animate-slide-up {
          animation: slide-up 0.3s ease-out;
        }
      `}</style>
    </div>
  );
};

